"""Database module — NEW builder-pattern API.

This module has been completely rewritten. The old procedural API is gone.
Do NOT modify this file.
"""


class QueryError(Exception):
    """Raised when a database query fails."""
    pass


class SelectBuilder:
    """Builder for SELECT queries."""
    def __init__(self, db, table):
        self._db = db
        self._table = table
        self._filter = None
        self._join_table = None
        self._join_on = None

    def where(self, filter_dict):
        self._filter = filter_dict
        return self

    def join(self, other_table, on=None):
        self._join_table = other_table
        self._join_on = on
        return self

    def execute(self):
        rows = self._db._tables.get(self._table, [])
        if self._filter:
            rows = [
                r for r in rows
                if all(r.get(k) == v for k, v in self._filter.items())
            ]
        if self._join_table and self._join_on:
            other_rows = self._db._tables.get(self._join_table, [])
            joined = []
            for row in rows:
                for other in other_rows:
                    if row.get(self._join_on) == other.get(self._join_on):
                        merged = {}
                        merged.update(row)
                        merged.update(other)
                        joined.append(merged)
            return joined
        return list(rows)

    def count(self):
        return len(self.execute())


class InsertBuilder:
    """Builder for INSERT operations."""
    def __init__(self, db, table):
        self._db = db
        self._table = table
        self._data = None

    def values(self, data):
        self._data = data
        return self

    def execute(self):
        if self._data is None:
            raise QueryError("No values provided for insert")
        if self._table not in self._db._tables:
            self._db._tables[self._table] = []
        row = dict(self._data)
        self._db._tables[self._table].append(row)
        return row


class UpdateBuilder:
    """Builder for UPDATE operations."""
    def __init__(self, db, table):
        self._db = db
        self._table = table
        self._data = None
        self._filter = None

    def set(self, data):
        self._data = data
        return self

    def where(self, filter_dict):
        self._filter = filter_dict
        return self

    def execute(self):
        if self._data is None:
            raise QueryError("No data provided for update")
        rows = self._db._tables.get(self._table, [])
        updated = 0
        for row in rows:
            if self._filter and not all(row.get(k) == v for k, v in self._filter.items()):
                continue
            row.update(self._data)
            updated += 1
        return updated


class DeleteBuilder:
    """Builder for DELETE operations."""
    def __init__(self, db, table):
        self._db = db
        self._table = table
        self._filter = None

    def where(self, filter_dict):
        self._filter = filter_dict
        return self

    def delete(self):
        if self._table not in self._db._tables:
            return 0
        rows = self._db._tables[self._table]
        if self._filter:
            original = len(rows)
            self._db._tables[self._table] = [
                r for r in rows
                if not all(r.get(k) == v for k, v in self._filter.items())
            ]
            return original - len(self._db._tables[self._table])
        else:
            count = len(rows)
            self._db._tables[self._table] = []
            return count


class NewDatabase:
    """Database connection using builder-pattern API.

    Usage:
        db = NewDatabase.connect(host='localhost', port=5432)
        results = db.select('users').where({'active': True}).execute()
        db.into('users').values({'name': 'Alice'}).execute()
        db.table('users').set({'name': 'Bob'}).where({'id': 1}).execute()
        db.from_table('users').where({'id': 1}).delete()
        count = db.select('users').where({'active': True}).count()
        results = db.select('users').join('orders', on='user_id').execute()
    """

    def __init__(self):
        self._tables = {}
        self._connected = False
        self.host = None
        self.port = None

    @classmethod
    def connect(cls, host='localhost', port=5432):
        """Create a new database connection."""
        db = cls()
        db.host = host
        db.port = port
        db._connected = True
        return db

    def select(self, table):
        """Start a SELECT query."""
        if not self._connected:
            raise QueryError("Not connected")
        return SelectBuilder(self, table)

    def into(self, table):
        """Start an INSERT operation."""
        if not self._connected:
            raise QueryError("Not connected")
        return InsertBuilder(self, table)

    def table(self, table):
        """Start an UPDATE operation."""
        if not self._connected:
            raise QueryError("Not connected")
        return UpdateBuilder(self, table)

    def from_table(self, table):
        """Start a DELETE operation."""
        if not self._connected:
            raise QueryError("Not connected")
        return DeleteBuilder(self, table)

seed_files.user_service.py:
"""User management service.

Uses the old-style Database API.
"""
from new_api import Database, DatabaseError


def create_user_store():
    """Create a database connection for the user store."""
    db = Database('localhost', 5432)
    return db


def find_user(db, username):
    """Find a user by username."""
    results = db.query('users', {'username': username})
    if results:
        return results[0]
    return None


def create_user(db, username, email, role='member'):
    """Create a new user. Raises DatabaseError if user already exists."""
    existing = db.query('users', {'username': username})
    if existing:
        raise DatabaseError(f"User {username} already exists")
    user_data = {'username': username, 'email': email, 'role': role, 'active': True}
    return db.insert('users', user_data)


def update_user_email(db, username, new_email):
    """Update a user's email address."""
    count = db.update('users', {'username': username}, {'email': new_email})
    if count == 0:
        raise DatabaseError(f"User {username} not found")
    return count


def deactivate_user(db, username):
    """Deactivate a user account."""
    return db.update('users', {'username': username}, {'active': False})


def count_active_users(db):
    """Count all active users."""
    return db.count('users', {'active': True})

