"""Order processing service.

Uses the old-style Database API.
"""
from new_api import Database, DatabaseError


def create_order_db():
    """Create a database connection for orders."""
    db = Database('localhost', 5432)
    return db


def find_orders_for_customer(db, customer_id):
    """Find all orders for a given customer."""
    return db.query('orders', {'customer_id': customer_id})


def place_order(db, customer_id, product, quantity, price):
    """Place a new order."""
    order_data = {
        'customer_id': customer_id,
        'product': product,
        'quantity': quantity,
        'total': quantity * price,
        'status': 'pending'
    }
    return db.insert('orders', order_data)


def cancel_order(db, order_id):
    """Cancel an order by deleting it. Returns number of orders deleted."""
    return db.delete('orders', {'id': order_id})


def get_orders_with_users(db):
    """Join orders with users table to get customer details."""
    return db.join('orders', 'users', on='customer_id')
